+import type { ConfigurableTrait, Trait, TraitRecord } from '../trait/types';
+import type { World } from './types';
+
+type Command =
+    | { type: 'spawn'; entity: Entity; traits: ConfigurableTrait[]; cancelled?: boolean }
+    | { type: 'destroy'; entity: Entity }
+    | { type: 'add'; entity: Entity; traits: ConfigurableTrait[] }
+    | { type: 'remove'; entity: Entity; traits: (Trait | RelationPair)[] }
+    | { type: 'exclusive'; entity: Entity; pair: RelationPair };
+
+type Scope = { commands: Command[]; spawned: Set<Entity> };
+
+export type DeferredWorld = {
+    spawn(...traits: ConfigurableTrait[]): Entity;
+    destroy(entity: Entity): void;
+    add(entity: Entity, ...traits: ConfigurableTrait[]): void;
+    remove(entity: Entity, ...traits: (Trait | RelationPair)[]): void;
+    addExclusive(entity: Entity, pair: RelationPair): void;
+    flush(): void;
+};
+
+export type DeferredState = {
+    root: Scope;
+    scopes: Scope[];
+    isFlushing: boolean;
+    api: DeferredWorld;
+};
+
+function current(state: DeferredState) {
+    return state.scopes.at(-1) ?? state.root;
+}
+
+function allScopes(state: DeferredState) {
+    return [state.root, ...state.scopes];
+}
+
+export function createDeferred(world: World): DeferredState {
+    const state = {
+        root: { commands: [], spawned: new Set<Entity>() },
+        scopes: [],
+        isFlushing: false,
+        api: null!,
+    } as DeferredState;
+
+    state.api = {
+        spawn(...traits) {
+            const scope = current(state);
+            // Reserve an id now so commands recorded later can refer to the entity. It is not
+            // added to queries or initialized until playback.
+            const entity = allocateEntity(world[$internal].entityIndex);
+            world[$internal].entityTraits.set(entity, new Set());
+            scope.spawned.add(entity);
+            scope.commands.push({ type: 'spawn', entity, traits });
+            return entity;
+        },
+        destroy(entity) {
+            const scope = current(state);
+            const spawn = scope.commands.find(
+                (command): command is Extract<Command, { type: 'spawn' }> =>
+                    command.type === 'spawn' && command.entity === entity && !command.cancelled
+            );
+            if (spawn) {
+                spawn.cancelled = true;
+                scope.spawned.delete(entity);
+                world[$internal].entityTraits.delete(entity);
+                releaseEntity(world[$internal].entityIndex, entity);
+                return;
+            }
+            scope.commands.push({ type: 'destroy', entity });
+        },
+        add(entity, ...traits) {
+            current(state).commands.push({ type: 'add', entity, traits });
+        },
+        remove(entity, ...traits) {
+            current(state).commands.push({ type: 'remove', entity, traits });
+        },
+        addExclusive(entity, pair) {
+            current(state).commands.push({ type: 'exclusive', entity, pair });
+        },
+        flush() {
+            flushScope(world, state, current(state));
+        },
+    };
+    return state;
+}
+
+export function enterDeferredScope(world: World) {
+    world[$internal].deferred.scopes.push({ commands: [], spawned: new Set<Entity>() });
+}
+
+export function exitDeferredScope(world: World) {
+    const state = world[$internal].deferred;
+    const scope = state.scopes.at(-1);
+    if (!scope) return;
+    try {
+        flushScope(world, state, scope);
+    } finally {
+        state.scopes.pop();
+    }
+}
+
+export function flushDeferredForEntity(world: World, entity: Entity) {
+    const state = world[$internal].deferred;
+    if (state.isFlushing) return;
+    if (allScopes(state).some((scope) => scope.commands.some((command) => command.entity === entity))) {
+        // Playback order is always older scopes first. A non-deferred mutation is an
+        // explicit synchronization point, so it commits every pending scope.
+        for (const scope of allScopes(state)) flushScope(world, state, scope);
+    }
+}
+
+export function deferredHas(world: World, entity: Entity, trait: Trait | RelationPair): boolean | undefined {
+    const state = world[$internal].deferred;
+    if (!allScopes(state).some((scope) => scope.commands.some((command) => command.entity === entity))) return;
+    let alive = world.has(entity);
+    let result = isRelationPair(trait)
+        ? entity.has(trait)
+        : hasTrait(world, entity, trait);
+    for (const scope of allScopes(state)) {
+        for (const command of scope.commands) {
+            if (command.entity !== entity) continue;
+            if (command.type === 'spawn') alive = !command.cancelled;
+            if (command.type === 'destroy') alive = false;
+            if (!alive) continue;
+            if (command.type === 'add') {
+                for (const config of command.traits) {
+                    if (matches(config, trait)) result = !isWildcard(config);
+                }
+            } else if (command.type === 'remove') {
+                for (const config of command.traits) if (matches(config, trait)) result = false;
+            } else if (command.type === 'exclusive') {
+                const relation = command.pair[$internal].relation;
+                if (isRelationPair(trait) && trait[$internal].relation === relation) {
+                    result = trait[$internal].target === command.pair[$internal].target && trait[$internal].target !== '*';
+                }
+            }
+        }
+    }
+    return alive && result;
+}
+
+export function deferredGet(world: World, entity: Entity, trait: Trait | RelationPair): TraitRecord<any> | undefined {
+    const present = deferredHas(world, entity, trait);
+    if (present === undefined) return;
+    if (!present) return undefined;
+    let value: any = getTrait(world, entity, trait) ?? {};
+    for (const scope of allScopes(world[$internal].deferred)) {
+        for (const command of scope.commands) {
+            if (command.entity !== entity || command.type !== 'add') continue;
+            for (const config of command.traits) {
+                if (!matches(config, trait) || !Array.isArray(config)) continue;
+                // Deferred values are merged exactly as addTrait does for SoA traits.
+                value = { ...value, ...config[1] };
+            }
+        }
+    }
+    return value;
+}
+
+function matches(config: ConfigurableTrait | Trait | RelationPair, requested: Trait | RelationPair) {
+    const item = Array.isArray(config) ? config[0] : config;
+    if (isRelationPair(item) || isRelationPair(requested)) {
+        if (!isRelationPair(item) || !isRelationPair(requested)) return false;
+        return (
+            item[$internal].relation === requested[$internal].relation &&
+            (item[$internal].target === '*' || item[$internal].target === requested[$internal].target)
+        );
+    }
+    return item === requested;
+}
+
+function isWildcard(config: ConfigurableTrait) {
+    return isRelationPair(config) && config[$internal].target === '*';
+}
+
+function flushScope(world: World, state: DeferredState, scope: Scope) {
+    if (scope.commands.length === 0 || state.isFlushing) return;
+    const commands = scope.commands.splice(0);
+    state.isFlushing = true;
+    try {
